# Module providing validation utilities

from geometry import IShape

class ValidationResult:
    is_valid: bool
    message: str

    def __init__(self, valid: bool, msg: str):
        self.is_valid = valid
        self.message = msg

class ShapeValidator:
    min_area: float

    def __init__(self, min_area: float):
        self.min_area = min_area

    def validate_shape(self, shape: IShape) -> ValidationResult:
        calculated_area: float = shape.area()
        if calculated_area >= self.min_area:
            return ValidationResult(True, "Shape meets minimum area requirement")
        else:
            return ValidationResult(False, "Shape too small")

def validate_number(value: int, min_val: int, max_val: int) -> bool:
    return value >= min_val and value <= max_val

