# Module providing formatting utilities for shapes

from geometry import IShape, Circle, Rectangle

class ShapeFormatter:
    precision: int

    def __init__(self, prec: int):
        self.precision = prec

    def format_area(self, shape: IShape) -> str:
        area_val: float = shape.area()
        perim_val: float = shape.perimeter()
        return f"Area: {area_val}, Perimeter: {perim_val}"

def get_shape_type_name(shape: IShape) -> str:
    if isinstance(shape, Circle):
        return "Circle"
    elif isinstance(shape, Rectangle):
        return "Rectangle"
    else:
        return "Unknown"
